function fibonacciIterative(n) {
  let result = [];
  result[0] = 0;
  result[1] = 1;
  for (let i = 2; i <= n; i++) {
    result[i] = result[i - 1] + result[i - 2];
  }
  return result[n];
}

// Recursive Fibonacci (Memoized)
const cache = {};
const fibonacciMemoized = function() {
  cache = {};
  return function(n) {
    if (n < 2) return n;
    if (cache[n] !== undefined) return cache[n];
    cache[n] = fibonacciMemoized(n - 1) + fibonacciMemoized(n - 2);
    return cache[n];
  };
}();

